func healthColor(failed, total int64) string {
	if total == 0 {
		return "bg-green-500"
	}
	rate := float64(failed) / float64(total) * 100
	if rate < 5 {
		return "bg-green-500"
	}
	if rate < 20 {
		return "bg-yellow-500"
	}
	return "bg-red-500"
}

func healthLabel(failed, total int64) string {
	if total == 0 {
		return "No activity"
	}
	rate := float64(failed) / float64(total) * 100
	if rate < 5 {
		return "Healthy"
	}
	if rate < 20 {
		return "Degraded"
	}
	return "Unhealthy"
}

